        "lyrics": "<p><span style=\"color:#0000FF\"><strong>1.</strong></span></p>\n\n<p><span style=\"color:#0000FF\">Gió th&igrave; thầm sông núi</span></p>\n\n<p><span style=\"color:#0000FF\">Giọng ân t&igrave;nh nỉ non</span></p>\n\n<p><span style=\"color:#0000FF\">Lặng nh&igrave;n em lần cuối</span></p>\n\n<p><span style=\"color:#0000FF\">Rồi cất bước ra đi.</span></p>\n\n<p><span style=\"color:#0000FF\"><strong>2.</strong></span></p>\n\n<p><span style=\"color:#0000FF\">Gió lùa trên tóc rối</span></p>\n\n<p><span style=\"color:#0000FF\">Lạnh thấm đôi vai gầy</span></p>\n\n<p><span style=\"color:#0000FF\">Mai này ai khoát áo</span></p>\n\n<p><span style=\"color:#0000FF\">Giữ ấm cho em tôi?</span></p>\n\n<p><span style=\"color:#0000FF\"><strong>ĐK: </strong></span></p>\n\n<p><span style=\"color:#0000FF\">Người đi trong đêm vắng</span></p>\n\n<p><span style=\"color:#0000FF\">Lòng nặng gánh yêu thương</span></p>\n\n<p><span style=\"color:#0000FF\">Chân trần in cát trắng</span></p>\n\n<p><span style=\"color:#0000FF\">Vội vượt suối băng ngàn.</span></p>\n\n<p><span style=\"color:#0000FF\">Ai giả vờ im lặng</span></p>\n\n<p><span style=\"color:#0000FF\">Thầm tiễn biệt người đi</span></p>\n\n<p><span style=\"color:#0000FF\">Bóng tối vương đầy mắt</span></p>\n\n<p><span style=\"color:#0000FF\">Nhạt nhòa lệ thấm mi.</span></p>\n\n<p><span style=\"color:#0000FF\"><strong>3.</strong></span></p>\n\n<p><span style=\"color:#0000FF\">Đêm sương pha màu áo</span></p>\n\n<p><span style=\"color:#0000FF\">Tiếng sóng vỗ r&igrave; rào</span></p>\n\n<p><span style=\"color:#0000FF\">Người qua dòng sanh tử</span></p>\n\n<p><span style=\"color:#0000FF\">Bỏ lại c&otilde;i chiêm bao.</span></p>",
