        "lyrics": "<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Gió thổi sóng dâng cao</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Đau lòng bờ cát trắng</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Bao giờ biển khô cạn</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Cát trắng về bến không.</span></p>\n\n<p><span style=\"color:#000080\">Chắp tay hỏi Thế Tôn</span></p>\n\n<p><span style=\"color:#000080\">Địa ngục bao nhiêu tầng</span></p>\n\n<p><span style=\"color:#000080\">Ở đâu không đường ác</span></p>\n\n<p><span style=\"color:#000080\">Không vị oán sinh thân?</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Tâm niệm vừa mới phát</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Phật hiện giữa hư không</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Phóng từ quang chiếu sáng</span></p>\n\n<p style=\"margin-left:.5in\"><span style=\"color:#000080\">Đạo tràng Phật mươi phương.</span></p>\n\n<p style=\"margin-left:1.0in\"><span style=\"color:#000080\">Hương Cực Lạc thơm ngát</span></p>\n\n<p style=\"margin-left:1.0in\"><span style=\"color:#000080\">Rực rỡ đóa sen hồng</span></p>\n\n<p style=\"margin-left:1.0in\"><span style=\"color:#000080\">Xin nhất tâm chánh thọ</span></p>\n\n<p style=\"margin-left:1.0in\"><span style=\"color:#000080\">Nguyện sanh về Tây phương.</span></p>\n\n<p><span style=\"color:#000080\">Về Tây phương, Hãy về Tây phương</span></p>\n\n<p><span style=\"color:#000080\">Dự vào hàng bất thối tín tâm</span></p>\n\n<p><span style=\"color:#000080\">Tiêu dao cùng Bồ tát</span></p>\n\n<p><span style=\"color:#000080\">Sáu thời thường an vui.</span></p>",
        "composer": "Thích Huyền Châu",
        "musician": "Phương Nguyễn",
        "arrangement": "Phương Nguyễn",
        "singer": "Nguyên Khang",
